external_knowledge:
- "lesser-known nations" refers to countries with populations under 5 million;
- "navigating the waves of demographic change" metaphorically represents the countries experiencing changes in population;
- "tides of their yearly population fluctuation" represents the yearly percentage change in population;
- "urban growth rate" signifies the annual growth rate of the urban population;
- "global pecking order" refers to the rank of the countries based on their population size.

sql:
SELECT country_name
FROM countries
WHERE world_population_share > 1;

SELECT COUNT(*) 
FROM countries 
WHERE density > 1000;

SELECT EXP(year_id) AS growth_factor, world_population 
FROM world_population 
WHERE year = 2020;

SELECT SUM(current_population) AS total_population
FROM countries
WHERE country_id IN (
    SELECT country_id FROM density_data WHERE density = (
        SELECT MAX(density) FROM density_data
    )
);

SELECT country_name 
FROM countries 
WHERE density = (SELECT MAX(density) FROM countries);
